import React from "react";
import "./Style.css";

const categories = [
  "Vegetables",
  "Fruits",
  "Dairy",
  "Bakery",
  "Snacks",
  "Beverages",
  "Household",
  "Frozen",
  "Personal Care",
];

const GroceryCategories = () => {
  return (
    <div className="category-section">
      <h3>Available grocery categories in Grocify</h3>
      <p>Add items from categories like vegetables, fruits, dairy, snacks, beverages, household and more.</p>
      <div className="category-list">
        {categories.map((category) => (
          <span key={category} className="category-pill">
            {category}
          </span>
        ))}
      </div>
    </div>
  );
};

export default GroceryCategories;
